import React, { useMemo, useState } from 'react';
import './UserManagement.css';

const USERS_KEY = 'mangauz_admin_users_v1';

const defaultUsers = [
  { id: 1, username: 'darlingohioo', email: 'ruhiddinov03@mail.com', level: 5, points: 9800, role: 'admin', status: 'active', joinDate: '2023-02-12' },
  { id: 2, username: 'DarkLord', email: 'darklord@mail.com', level: 5, points: 12500, role: 'user', status: 'active', joinDate: '2023-01-15' },
  { id: 3, username: 'MangaMaster', email: 'master@mail.com', level: 5, points: 9800, role: 'moderator', status: 'active', joinDate: '2023-02-20' },
  { id: 4, username: 'WeebQueen', email: 'queen@mail.com', level: 4, points: 7200, role: 'user', status: 'active', joinDate: '2023-03-10' }
];

const loadUsers = () => {
  const raw = localStorage.getItem(USERS_KEY);
  if (!raw) {
    localStorage.setItem(USERS_KEY, JSON.stringify(defaultUsers));
    return defaultUsers;
  }
  try {
    return JSON.parse(raw);
  } catch {
    return defaultUsers;
  }
};

const persistUsers = (users) => localStorage.setItem(USERS_KEY, JSON.stringify(users));

const UserManagement = () => {
  const [users, setUsers] = useState(loadUsers);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedUsers, setSelectedUsers] = useState([]);

  const filteredUsers = useMemo(
    () =>
      users.filter(
        (user) =>
          user.username.toLowerCase().includes(searchTerm.toLowerCase()) ||
          user.email.toLowerCase().includes(searchTerm.toLowerCase())
      ),
    [users, searchTerm]
  );

  const updateUser = (userId, patch) => {
    setUsers((prev) => {
      const next = prev.map((u) => (u.id === userId ? { ...u, ...patch } : u));
      persistUsers(next);
      return next;
    });
  };

  const deleteUser = (userId) => {
    setUsers((prev) => {
      const next = prev.filter((u) => u.id !== userId);
      persistUsers(next);
      return next;
    });
  };

  return (
    <div className="user-management">
      <h2>User Management</h2>

      <div className="management-header">
        <div className="search-box">
          <i className="fas fa-search"></i>
          <input placeholder="Search users..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
        </div>
      </div>

      <div className="users-table-container">
        <table className="users-table">
          <thead>
            <tr>
              <th>
                <input
                  type="checkbox"
                  checked={selectedUsers.length === filteredUsers.length && filteredUsers.length > 0}
                  onChange={() =>
                    setSelectedUsers(
                      selectedUsers.length === filteredUsers.length ? [] : filteredUsers.map((u) => u.id)
                    )
                  }
                />
              </th>
              <th>User</th>
              <th>Level</th>
              <th>Role</th>
              <th>Status</th>
              <th>Registered</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredUsers.map((user) => (
              <tr key={user.id}>
                <td>
                  <input
                    type="checkbox"
                    checked={selectedUsers.includes(user.id)}
                    onChange={() =>
                      setSelectedUsers((prev) =>
                        prev.includes(user.id) ? prev.filter((id) => id !== user.id) : [...prev, user.id]
                      )
                    }
                  />
                </td>
                <td>
                  <div className="user-cell">
                    <div className="user-avatar">{user.username[0]}</div>
                    <div className="user-info">
                      <div className="username">{user.username}</div>
                      <div className="user-email">{user.email}</div>
                    </div>
                  </div>
                </td>
                <td>
                  <div className="level-cell">
                    <span className="level-badge">Level {user.level}</span>
                    <span className="points">{user.points} pts</span>
                  </div>
                </td>
                <td>
                  <select value={user.role} onChange={(e) => updateUser(user.id, { role: e.target.value })} className="role-select">
                    <option value="user">User</option>
                    <option value="moderator">Moderator</option>
                    <option value="admin">Admin</option>
                  </select>
                </td>
                <td>
                  <select value={user.status} onChange={(e) => updateUser(user.id, { status: e.target.value })} className={`status-select ${user.status}`}>
                    <option value="active">Active</option>
                    <option value="suspended">Suspended</option>
                    <option value="inactive">Inactive</option>
                  </select>
                </td>
                <td>{user.joinDate}</td>
                <td>
                  <div className="action-buttons-cell">
                    <button className="icon-btn delete" onClick={() => deleteUser(user.id)} title="Delete user">
                      <i className="fas fa-trash"></i>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default UserManagement;
